// Fungsi untuk menghitung CRC16 CCITT
function calculateCRC16($str) {
    $crc = 0xFFFF;
    for ($c = 0; $c < strlen($str); $c++) {
        $crc ^= ord($str[$c]) << 8;
        for ($i = 0; $i < 8; $i++) {
            if ($crc & 0x8000) {
                $crc = ($crc << 1) ^ 0x1021;
            } else {
                $crc = $crc << 1;
            }
        }
    }
    $hex = $crc & 0xFFFF;
    return strtoupper(str_pad(dechex($hex), 4, '0', STR_PAD_LEFT));
}

// Fungsi untuk menyisipkan nominal ke String QRIS
function generateDynamicQRIS($qris_string, $nominal) {
    // 1. Potong 4 digit CRC lama di paling belakang
    $qris_string = substr($qris_string, 0, -4);
    
    // 2. Siapkan tag 54 (Nominal)
    $nominal_str = (string) $nominal;
    $panjang_nominal = str_pad(strlen($nominal_str), 2, '0', STR_PAD_LEFT);
    $tag_54 = "54" . $panjang_nominal . $nominal_str;
    
    // 3. Sisipkan tag 54 tepat sebelum tag 58 (Country Code '5802ID')
    $parts = explode("5802ID", $qris_string);
    
    if (count($parts) >= 2) {
        $before_58 = $parts[0];
        // Cek dan hapus jika sebelumnya sudah ada tag 54 (berjaga-jaga)
        if (preg_match('/54(\d{2})(\d+)$/', $before_58, $matches)) {
            $before_58 = substr($before_58, 0, -strlen($matches[0]));
        }
        // Gabungkan kembali dengan nominal baru
        $new_qris = $before_58 . $tag_54 . "5802ID" . $parts[1];
    } else {
        // Fallback jika format tidak standar (kembalikan aslinya)
        $new_qris = $qris_string;
    }
    
    // 4. Hitung ulang dan tempelkan CRC baru
    return $new_qris . calculateCRC16($new_qris);
}
