        FROM transaksi t 
        JOIN pelanggan p ON t.pelanggan_id = p.id 
        WHERE t.uuid = ?
    ", [$uuid]);
} elseif ($transaksi_id_lama) {
    // Fallback: Cari berdasarkan ID lama
