        SELECT t.*, p.nama as nama_customer, p.nomor_wa, p.email 
        FROM transaksi t 
        JOIN pelanggan p ON t.pelanggan_id = p.id 
        WHERE t.id = ?
    ", [$transaksi_id_lama]);
} else {
    redirect('index.php');
}

