// Send invoice message if first time
if ($transaksi['is_invoice_sent'] == 0 && $transaksi['status'] === 'pending') {
    
    $template = fetchRow("SELECT isi_pesan FROM template_pesan_produk WHERE produk_id = ? AND jenis_pesan = 'invoice'", [$main_product['produk_id']]);
    
