                $produk_list[] = [
                    'nama' => $produk['nama'],
                    'harga' => $produk['harga'],
                    'link_akses' => $produk['link_akses']
                ];
            }
            $template_data['produk_list'] = $produk_list;
        } else {
            $template_data['nama_produk'] = $main_product['nama'];
            $template_data['harga_produk'] = $main_product['harga'];
            $template_data['link_akses'] = $main_product['link_akses'];
        }
        
        $message = replaceTemplatePlaceholders($template['isi_pesan'], $template_data);
        $account_name = $main_product['onesender_account'] ?? 'default';
        
        // Eksekusi kirim pesan
        $result = sendWhatsAppText($transaksi['nomor_wa'], $message, $account_name);
        
        // UPDATE DATABASE: Tandai sudah dikirim (set jadi 1)
        // Kita lakukan update ini terlepas dari sukses/gagal kirim, 
        // untuk menghindari spamming jika WA gateway error.
        execute("UPDATE transaksi SET is_invoice_sent = 1 WHERE id = ?", [$transaksi_id]);
        
